270	  template <class ProblemShape>
271	  static constexpr Params
272	  to_underlying_arguments(
273	      ProblemShape const& problem_shape,
274	      Arguments const& args,
275	      [[maybe_unused]] void* workspace) {
276	    // Optionally append 1s until problem shape is rank-4 in case its is only rank-3 (MNK)
277	    auto problem_shape_MNKL = append<4>(problem_shape, 1);
278	    auto [M, N, K, L] = problem_shape_MNKL;
279	
280	    uint32_t transaction_bytes = TmaTransactionBytes;
281	    typename Params::TMA_C tma_load_c{};
282	    if constexpr (is_source_supported) {
283	      Tensor tensor_c = make_tensor(make_gmem_ptr<TmaElementC const>(args.ptr_C), make_layout(make_shape(M,N,L), args.dC));
284	      tma_load_c = make_tma_copy_C_sm90(
285	          CopyOpG2S{},
286	          tensor_c,
287	          take<0,2>(SmemLayoutC{}),
288	          EpilogueTile{});
289	    }
290	
291	    typename Params::TMA_D tma_store_d{};
292	    if constexpr (is_destination_supported) {
293	      Tensor tensor_d = make_tensor(make_gmem_ptr<TmaElementD>(args.ptr_D), make_layout(make_shape(M,N,L), args.dD));
294	      tma_store_d = make_tma_copy_C_sm90(
295	          CopyOpS2G{},
296	          tensor_d,
297	          take<0,2>(SmemLayoutD{}),
298	          EpilogueTile{});
299	    }
300	
301	    return {
302	      FusionCallbacks::to_underlying_arguments(problem_shape, args.thread, workspace),
303	      tma_load_c,
304	      tma_store_d,
305	      transaction_bytes
306	    };
307	  }
