322	  template <class ProblemShape>
323	  static bool
324	  can_implement(
325	      ProblemShape const& problem_shape,
326	      [[maybe_unused]] Arguments const& args) {
327	    auto problem_shape_MNKL = append<4>(problem_shape, 1);
328	    auto [M,N,K,L] = problem_shape_MNKL;
329	    auto shape = cute::make_shape(M,N,L);
330	
331	    bool implementable = true;
332	    if constexpr (is_destination_supported) {
333	      constexpr int tma_alignment_bits_D = cutlass::detail::get_output_alignment_bits<ElementD>();
334	      constexpr int min_tma_aligned_elements_D = tma_alignment_bits_D / cutlass::sizeof_bits<ElementD>::value;
335	      if constexpr (cute::is_same_v<CopyOpS2G, SM90_TMA_STORE_IM2COL>) { // ignore L stride for implicit gemm
336	        implementable = cutlass::detail::check_alignment<min_tma_aligned_elements_D>(take<0,2>(shape), take<0,2>(StrideD{}));
337	      }
338	      else {
339	        implementable = cutlass::detail::check_alignment<min_tma_aligned_elements_D>(shape, StrideD{});
340	      }
341	    }
342	
343	    if constexpr (not cute::is_void_v<ElementC>) {
344	      constexpr int tma_alignment_bits_C = cutlass::detail::get_input_alignment_bits<ElementC>();
345	      constexpr int min_tma_aligned_elements_C = tma_alignment_bits_C / cutlass::sizeof_bits<ElementC>::value;
346	      if constexpr (cute::is_same_v<CopyOpG2S, SM90_TMA_LOAD_IM2COL>) { // ignore L stride for implicit gemm
347	        implementable = implementable && cutlass::detail::check_alignment<min_tma_aligned_elements_C>(take<0,2>(shape), take<0,2>(StrideC{}));
348	      }
349	      else {
350	        implementable = implementable && cutlass::detail::check_alignment<min_tma_aligned_elements_C>(shape, StrideC{});
351	      }
352	    }
353	
354	    if (!implementable) {
355	      CUTLASS_TRACE_HOST("  CAN IMPLEMENT: Problem Size doesn't meet the minimum alignment requirements for TMA.\n");
356	    }
357	
358	    bool fusion_implementable = FusionCallbacks::can_implement(problem_shape, args.thread);
359	
360	    if (!fusion_implementable) {
361	      CUTLASS_TRACE_HOST("  CAN IMPLEMENT: Problem Size doesn't meet the minimum requirements for FusionCallbacks.\n");
362	    }
363	
364	    bool beta_implementable = true;
365	
366	    if constexpr (cute::is_void_v<ElementC>) {
367	      if constexpr (detail::has_beta<Arguments>::value) {
368	        beta_implementable = args.thread.beta == 0.0;
369	      }
370	      if constexpr (detail::has_beta_ptr<Arguments>::value) {
371	        beta_implementable = beta_implementable && args.thread.beta_ptr == nullptr;
372	      }
373	    }
374	
375	    if (!beta_implementable) {
376	      CUTLASS_TRACE_HOST("  CAN IMPLEMENT: Beta/beta pointer was set, but epilogue is sourceless (void-C).\n");
377	    }
378	
379	    return implementable && fusion_implementable && beta_implementable;
380	  }
