419	  template<
420	    class ProblemShapeMNKL,
421	    class TileShapeMNK,
422	    class TileCoordMNKL,
423	    class TiledMma
424	  >
425	  CUTLASS_DEVICE auto
426	  load(
427	      LoadPipeline load_pipeline,
428	      LoadPipelineState load_pipe_producer_state,
429	      ProblemShapeMNKL problem_shape_mnkl,
430	      TileShapeMNK tile_shape_MNK,
431	      TileCoordMNKL tile_coord_mnkl,
432	      TiledMma tiled_mma,
433	      int thread_idx,
434	      TensorStorage& shared_tensors,
435	      int subtile_idx=-1) {
436	    using namespace cute;
437	
438	    // Indexing variables
439	    auto [M, N, K, L] = problem_shape_mnkl;
440	    auto [m_coord, n_coord, k_coord, l_coord] = tile_coord_mnkl;
441	
442	    // The tma tensor C under im2col mode only has two modes (M, N) which
443	    // should be local tiled with only (m_coord, n_coord).
444	    auto coord_shape = conditional_return<is_im2col_C>(
445	      make_coord(m_coord, n_coord),
446	      make_coord(m_coord, n_coord, l_coord));
447	
448	    // Represent the full source tensor, slice to get the tile this CTA is currently responsible for
449	    Tensor mC_mn = params.tma_load_c.get_tma_tensor(make_shape(M,N,L));                                //       (M,N,L)
450	    Tensor mC = coalesce(mC_mn, take<0,2>(CtaTileMNK{}));
451	    Tensor gC = local_tile(mC, take<0,2>(CtaTileMNK{}), coord_shape);                                  // (CTA_M,CTA_N)
452	
453	    // Apply epilogue subtile, get matching smem tensor
454	    auto ptr_sC = shared_tensors.collective.smem_C.begin();
455	    Tensor gC_epi = flat_divide(gC, EpilogueTile{});                             // (EPI_TILE_M,EPI_TILE_N,EPI_M,EPI_N)
456	    Tensor sC_epi = make_tensor(make_smem_ptr(ptr_sC), SmemLayoutC{});           //      (EPI_TILE_M,EPI_TILE_N,PIPE_C)
457	
458	    // Prepare the thread(b)lock's (G)mem to (S)mem TMA tiled copy (bGS_)
459	    ThrCopy thrblk_g2s = params.tma_load_c.get_slice(Int<0>{});
460	    Tensor bGS_gC = thrblk_g2s.partition_S(gC_epi);                                    // (G2S,G2S_M,G2S_N,EPI_M,EPI_N)
461	    Tensor bGS_sC = thrblk_g2s.partition_D(sC_epi);                                    // (G2S,G2S_M,G2S_N,PIPE_C)
462	
463	    // Get the fusion callbacks for the producer load warp
464	    auto pld_args = cutlass::epilogue::fusion::detail::ProducerLoadArgs(
465	                      problem_shape_mnkl,
466	                      CtaTileMNK{},
467	                      tile_coord_mnkl,
468	                      tiled_mma,
469	                      EpilogueTile{},
470	                      thread_idx
471	                    );
472	    auto pld_callbacks = fusion_callbacks.get_producer_load_callbacks(pld_args);
473	    bool is_C_load_needed = is_source_supported && fusion_callbacks.is_C_load_needed();
474	
475	    // Predication for TMA load (one thread issues TMA load)
476	    bool issue_tma_load = cute::elect_one_sync();
477	
478	    // Pre-loop fusion callback entry point
479	    pld_callbacks.begin();
480	
481	    CUTLASS_PRAGMA_UNROLL
482	    for (int epi_n = 0; epi_n < size<3>(gC_epi); ++epi_n) {
483	      CUTLASS_PRAGMA_UNROLL
484	      for (int epi_m = 0; epi_m < size<2>(gC_epi); ++epi_m) {
485	        if (subtile_idx != -1 && (epi_n * static_cast<int>(size<2>(gC_epi)) + epi_m) != subtile_idx) {
486	          continue;
487	        }
488	        // Acquire the lock for this stage
489	        constexpr uint16_t mcast_mask = 0;
490	        uint64_t* tma_barrier = load_pipeline.producer_get_barrier(load_pipe_producer_state);
491	        load_pipeline.producer_acquire(load_pipe_producer_state);
492	
493	        // Loop fusion callback entry point
494	        pld_callbacks.step(tma_barrier, epi_m, epi_n, load_pipe_producer_state.count(), issue_tma_load);
495	
496	        // Execute the TMA load for C if needed
497	        if (issue_tma_load && is_C_load_needed) {
498	          copy(params.tma_load_c.with(*tma_barrier, mcast_mask),
499	              bGS_gC(_,_,_,epi_m,epi_n), bGS_sC(_,_,_,load_pipe_producer_state.index()));
500	          load_pipeline.producer_expect_transaction(load_pipe_producer_state);
501	        }
502	
503	        // Commit TMA loads for this stage and release the lock
504	        load_pipeline.producer_commit(load_pipe_producer_state);
505	        ++load_pipe_producer_state;
506	      }
507	    }
508	
509	    // Post-loop fusion callback entry point
510	    pld_callbacks.end();
511	
512	    return load_pipe_producer_state;
513	  }
514	
515	  CUTLASS_DEVICE auto
516	  load_tail(
517	      LoadPipeline load_pipeline,
518	      LoadPipelineState load_pipe_producer_state) {
519	    bool issue_tma_load = cute::elect_one_sync();
520	    if (issue_tma_load) {
521	      load_pipeline.producer_tail(load_pipe_producer_state);
522	    }
523	
524	    return load_pipe_producer_state;
525	  }
526	
527	  template<
528	    class ProblemShapeMNKL,
529	    class TileShapeMNK,
530	    class TileCoordMNKL,
531	    class AccEngine, class AccLayout,
532	    class TiledMma
533	  >
534	  CUTLASS_DEVICE auto
535	  store(
536	      LoadPipeline load_pipeline,
537	      LoadPipelineState load_pipe_consumer_state,
538	      StorePipeline store_pipeline,
539	      StorePipelineState store_pipe_producer_state,
540	      ProblemShapeMNKL problem_shape_mnkl,
541	      TileShapeMNK tile_shape_MNK,
542	      TileCoordMNKL tile_coord_mnkl,
543	      cute::Tensor<AccEngine,AccLayout> accumulators,
544	      TiledMma tiled_mma,
545	      int thread_idx,
546	      TensorStorage& shared_tensors,
547	      int subtile_idx=-1) {
548	    using namespace cute;
549	    using ElementAccumulator = typename AccEngine::value_type;
550	    using ElementCompute_ = typename epilogue::fusion::FusionCallbacksTraits<FusionCallbacks>::ElementCompute;
551	    using ElementCompute = cute::conditional_t<cute::is_void_v<ElementCompute_>,ElementAccumulator,ElementCompute_>;
552	
553	    static_assert(is_rmem<AccEngine>::value, "Accumulator must be RF resident.");
554	    static_assert(rank(AccLayout{}) == 3, "Accumulator must be MMA-partitioned: (MMA,MMA_M,MMA_N)");
555	    static_assert(rank(ProblemShapeMNKL{}) == 4, "ProblemShapeMNKL must be rank 4");
556	    static_assert(is_static<TileShapeMNK>::value, "TileShapeMNK must be static");
557	    static_assert(rank(TileShapeMNK{}) == 3, "TileShapeMNK must be rank 3");
558	    static_assert(rank(TileCoordMNKL{}) == 4, "TileCoordMNKL must be rank 4");
559	
560	    // Indexing variables
561	    auto [M, N, K, L] = problem_shape_mnkl;
562	    auto [m_coord, n_coord, k_coord, l_coord] = tile_coord_mnkl;
563	
564	    // The tma tensor D under im2col mode only has two modes (M, N) which
565	    // should be local tiled with only (m_coord, n_coord).
566	    auto coord_shape = conditional_return<is_im2col_D>( 
567	        make_coord(m_coord, n_coord),
568	        make_coord(m_coord, n_coord, l_coord));
569	
570	    // Represent the full output tensor, slice to get the tile this CTA is responsible for
571	    Tensor mD_mn = params.tma_store_d.get_tma_tensor(make_shape(M,N,L));                               //       (M,N,L)
572	    Tensor mD = coalesce(mD_mn, take<0,2>(CtaTileMNK{}));
573	    Tensor gD = local_tile(mD, take<0,2>(CtaTileMNK{}), coord_shape);                                  // (CTA_M,CTA_N)
574	
575	    // Apply epilogue subtiling
576	    Tensor gD_epi = flat_divide(gD, EpilogueTile{});                             // (EPI_TILE_M,EPI_TILE_N,EPI_M,EPI_N)
577	
578	    // Construct the corresponding pipelined smem tensors
579	    auto ptr_sC = shared_tensors.collective.smem_C.begin();
580	    auto ptr_sD = shared_tensors.collective.smem_D.begin();
581	    Tensor sC_epi = cute::as_position_independent_swizzle_tensor(
582	                      make_tensor(make_smem_ptr(ptr_sC), SmemLayoutC{}));             // (EPI_TILE_M,EPI_TILE_N,PIPE_C)
583	    Tensor sD_epi = cute::as_position_independent_swizzle_tensor(
584	                      make_tensor(make_smem_ptr(ptr_sD), SmemLayoutD{}));             // (EPI_TILE_M,EPI_TILE_N,PIPE_D)
585	
586	    TiledCopy tiled_copy_C_atom = make_tiled_copy_C_atom(CopyAtomC{}, tiled_mma);
587	
588	    // (t)hread-partition for (r)egister to (r)egister copy (tRR_)
589	    TiledCopy tiled_r2r = [&]() CUTLASS_LAMBDA_FUNC_INLINE {
590	      if constexpr (IsUseR2R) {
591	        return make_tiled_copy_S(Copy_Atom<CopyOpR2R, ElementCompute>{}, tiled_copy_C_atom);
592	      }
593	      else {
594	        return make_tiled_copy_S(Copy_Atom<AutoVectorizingCopyWithAssumedAlignment<128>,
595	          ElementCompute>{}, tiled_copy_C_atom);
596	      }
597	    }();
598	    ThrCopy thread_r2r = tiled_r2r.get_slice(thread_idx);
599	
600	    // (t)hread-partition for (r)egister to (s)mem copy (tRS_)
601	    TiledCopy tiled_r2s = [&]() CUTLASS_LAMBDA_FUNC_INLINE {
602	      if constexpr (IsUseR2R) {
603	        return make_tiled_copy_D(Copy_Atom<CopyOpR2S,SmemElementD>{}, tiled_r2r);
604	      }
605	      else {
606	        return make_tiled_copy_S(Copy_Atom<CopyOpR2S,SmemElementD>{}, tiled_copy_C_atom);
607	      }
608	    }();
609	    ThrCopy thread_r2s = tiled_r2s.get_slice(thread_idx);
610	    Tensor tRS_rAcc = thread_r2s.retile_S(accumulators);                                   // ((R2S,R2S_V),MMA_M,MMA_N)
611	    Tensor tRS_sD   = thread_r2s.partition_D(sD_epi);                                       // (R2S,R2S_M,R2S_N,PIPE_D)
612	
613	    auto mma_tile_m = size<0>(TileShapeMNK{}) / size<1>(tRS_rAcc);
614	    auto mma_tile_n = size<1>(TileShapeMNK{}) / size<2>(tRS_rAcc);
615	    auto epi_tile_m = size<0>(EpilogueTile{});
616	    auto epi_tile_n = size<1>(EpilogueTile{});
617	
618	    // Allocate D registers
619	    Layout tRS_rD_layout = make_layout(take<0,3>(shape(thread_r2s.partition_S(sD_epi))));
620	    Tensor tRS_rD = make_tensor<SmemElementD>(tRS_rD_layout);                                      // (R2S,R2S_M,R2S_N)
621	
622	    // Vectorized fragment view
623	    constexpr int FragmentSize = DispatchPolicy::FragmentSize;
624	    Tensor tRS_rAcc_frg = recast<Array<ElementAccumulator, FragmentSize>>(tRS_rAcc);
625	    Tensor tRS_rD_frg   = recast<Array<SmemElementD      , FragmentSize>>(tRS_rD);
626	    CUTE_STATIC_ASSERT(size<0>(tRS_rAcc) % FragmentSize == 0, "Fragment size does not vectorize properly");
627	
628	    // (t)hread-partition for (s)mem to (r)egister copy (tSR_)
629	    TiledCopy tiled_s2r = make_tiled_copy_S(Copy_Atom<CopyOpS2R, SmemElementC>{}, tiled_copy_C_atom);
630	    ThrCopy thread_s2r = tiled_s2r.get_slice(thread_idx);
631	    Tensor tSR_sC        = thread_s2r.partition_S(sC_epi);                                  // (S2R,S2R_M,S2R_N,PIPE_C)
632	    Layout tSR_rC_layout = thread_s2r.retile_D(tRS_rD).layout();                            // (S2R,S2R_M,S2R_N)
633	
634	    // Allocate C registers
635	    // If C smem load is a non-vectorized dst(i) = src(i) then we can allocate C registers directly in the compute type
636	    // to eliminate some redundant pack+unpack instruction sequences for sub-word types
637	    constexpr bool IsDirectS2R = cute::is_same_v<CopyOpS2R, AutoVectorizingCopyWithAssumedAlignment<128>>
638	                                && decltype(max_common_vector(tSR_rC_layout, tSR_sC.layout()))::value <= 1;
639	    using RegisterElementC = cute::conditional_t<IsDirectS2R, ElementCompute, SmemElementC>;
640	    Tensor tRS_rC = make_tensor<RegisterElementC>(tRS_rD_layout);                                  // (R2S,R2S_M,R2S_N)
641	    Tensor tSR_rC = thread_s2r.retile_D(tRS_rC);                                                   // (S2R,S2R_M,S2R_N)
642	
643	    // thread(b)lock-partition for (s)mem to (g)mem copy (bSG_)
644	    ThrCopy thrblk_s2g = params.tma_store_d.get_slice(Int<0>{});
645	    Tensor bSG_sD = thrblk_s2g.partition_S(sD_epi);                                    // (S2G,S2G_M,S2G_N,PIPE_D)
646	    Tensor bSG_gD = thrblk_s2g.partition_D(gD_epi);                                    // (S2G,S2G_M,S2G_N,EPI_M,EPI_N)
647	
648	    // OOB predication for tile quantization "residue"
649	    // Absolute coordinate tensors (dynamic)
650	    Tensor mD_crd = make_identity_tensor(make_shape(M,N));                                                     // (M,N)
651	    Tensor cD_mn = local_tile(mD_crd, take<0,2>(CtaTileMNK{}), make_coord(m_coord, n_coord));          // (CTA_M,CTA_N)
652	    Tensor tRS_cD_mn = [&]() CUTLASS_LAMBDA_FUNC_INLINE {
653	      if constexpr (IsUseR2R) {
654	        // (t)hread-partition for ConsumerStoreCallbacks. 
655	        TiledCopy tiled_cst = make_tiled_copy_S(Copy_Atom<CopyOpR2S,SmemElementC>{}, tiled_copy_C_atom);
656	        ThrCopy thread_cst = tiled_cst.get_slice(thread_idx);
657	
658	        return thread_cst.partition_S(flat_divide(cD_mn, EpilogueTile{}));             // (R2S,R2S_M,R2S_N,EPI_M,EPI_N)
659	      }
660	      else {
661	        return thread_r2s.partition_S(flat_divide(cD_mn, EpilogueTile{}));             // (R2S,R2S_M,R2S_N,EPI_M,EPI_N)
662	      }
663	    }();
664	    // Relative coordinate tensors (static)
665	    Tensor cD = make_coord_tensor(cD_mn.layout());                                                     // (CTA_M,CTA_N)
666	    Tensor tRS_cD = make_coord_tensor(tRS_cD_mn.layout());                          // (R2S,R2S_M,R2S_N,EPI_M,EPI_N)
667	    // Subtract the global "bottom right" corner from the local "top left" corner to get the max relative coordinate
668	    auto residue_cD = make_coord(M,N) - cD_mn(_0{});                                                           // (m,n)
669	    auto residue_tRS_cD = make_coord(M,N) - tRS_cD_mn(_0{});                                                   // (m,n)
670	
671	    CUTE_STATIC_ASSERT(epi_tile_m % mma_tile_m == 0, "MMA_TILE_M must divide EPI_TILE_M");
672	
673	    if constexpr (epi_tile_m * epi_tile_n > mma_tile_m * mma_tile_n) {
674	      // When the epilogue subtile is larger than the MMA tiles, loop over multiple MMA tiles
675	      CUTE_STATIC_ASSERT(epi_tile_n % mma_tile_n == 0, "MMA_TILE_N must divide EPI_TILE_N");
676	    }
677	    else {
678	      CUTE_STATIC_ASSERT(mma_tile_n % epi_tile_n == 0, "EPI_TILE_N must divide MMA_TILE_N");
679	    }
680	
681	    // Get TiledCopy for partition reference when consumer store.
682	    TiledCopy tiled_copy_partition_ref = make_tiled_copy_S(Copy_Atom<CopyOpR2S,SmemElementD>{}, tiled_copy_C_atom);
683	    // Get the fusion callbacks for the consumer store warps
684	    constexpr bool RefSrc = true; // Register tensors reference tiled copy src layout
685	    auto cst_args = cutlass::epilogue::fusion::detail::ConsumerStoreArgs(
686	                      problem_shape_mnkl,
687	                      CtaTileMNK{},
688	                      tile_coord_mnkl,
689	                      tiled_mma,
690	                      EpilogueTile{},
691	                      tiled_copy_partition_ref,
692	                      cD,
693	                      residue_cD,
694	                      tRS_cD,
695	                      residue_tRS_cD,
696	                      tRS_rC,
697	                      thread_idx
698	                    );
699	    auto cst_callbacks = fusion_callbacks.template get_consumer_store_callbacks<RefSrc>(cst_args);
700	    bool is_producer_load_needed = fusion_callbacks.is_producer_load_needed();
701	    bool is_C_load_needed = is_source_supported && fusion_callbacks.is_C_load_needed();
702	
703	    using FragmentVisit = decltype(cst_callbacks.visit(tRS_rAcc_frg(0), 0, 0, 0));
704	    constexpr bool IsDirectR2S = cute::is_same_v<FragmentVisit, Array<SmemElementD, FragmentSize>>;
705	    using RegisterElementD = cute::conditional_t<!IsDirectR2S, ElementCompute, SmemElementD>;
706	    Tensor tRS_rCompute = make_tensor<RegisterElementD>(tRS_rD_layout);                            // (R2S,R2S_M,R2S_N)
707	    Tensor tRS_rCompute_frg = recast<Array<RegisterElementD, FragmentSize>>(tRS_rCompute);
708	
709	    // Thread synchronizer for previously issued waits or fences
710	    // to ensure visibility of smem reads/writes to threads or TMA unit
711	    auto synchronize = [&] () CUTLASS_LAMBDA_FUNC_INLINE { cutlass::arch::NamedBarrier::sync(size(TiledMma{}), cutlass::arch::ReservedNamedBarriers::EpilogueBarrier); };
712	
713	    // Predication for TMA store (one warp issues TMA store)
714	    bool issue_tma_store = (thread_idx / NumThreadsPerWarp) == 0;
715	
716	    // In the reuse smem configuration we have StagesC smem buffers and at most StagesD committed TMA stores in flight.
717	    // The TMA store pipeline producer acquire returns when at most StagesD-1 committed stores are in-flight, so we can
718	    // only guarantee store completion after StagesD iterations, then we can begin issuing releases on the smem buffer locks.
719	    // store_pipe_producer_state tracks the acquire and load_pipe_consumer_state tracks the release, in circular buffer fashion.
720	    LoadPipelineState load_wait_state = load_pipe_consumer_state;
721	    if constexpr (ReuseSmemC) {
722	      load_wait_state = store_pipe_producer_state;
723	      load_wait_state.phase_ ^= 1;
724	    }
725	
726	    // We can delay issue of TMA store by one iteration to achieve better interleaving of non-TMA instructions
727	    // Sync requirements of smem reuse may preclude this optimization
728	    // Delayed stores cause delayed stage releases which causes deadlock when StagesC == StagesD
729	    [[maybe_unused]] int epi_m_prev = 0;
730	    [[maybe_unused]] int epi_n_prev = 0;
731	    static_assert(not (DelayTmaStore and ReuseSmemC and StagesC <= StagesD), "This TMA epilogue configuration will deadlock");
732	
733	    // The TMA store sequence for one subtile iteration
734	    auto tma_store_fn = [&] (int epi_m, int epi_n) CUTLASS_LAMBDA_FUNC_INLINE {
735	      // Write the tile from smem to gmem with TMA
736	      cutlass::arch::fence_view_async_shared(); // ensure smem writes are visible to TMA
737	      synchronize(); // ensure all threads have issued their async fence
738	      if constexpr (is_destination_supported) {
739	        if (issue_tma_store) {
740	          copy(params.tma_store_d, bSG_sD(_,_,_,store_pipe_producer_state.index()), bSG_gD(_,_,_,epi_m,epi_n));
741	        }
742	      }
743	
744	      // Post async fence, pre TMA commit callback entry point
745	      cst_callbacks.tma_store(epi_m, epi_n, store_pipe_producer_state.count(), issue_tma_store);
746	
747	      // Commit the TMA stores for this stage
748	      if (issue_tma_store) {
749	        store_pipeline.producer_commit(store_pipe_producer_state);
750	      }
751	      ++store_pipe_producer_state;
752	      ++issued_stores;
753	
754	      if constexpr (ReuseSmemC) {
755	
756	        // Wait for the next smem buffer to be available
757	        if (issue_tma_store) {
758	          store_pipeline.producer_acquire(store_pipe_producer_state);
759	        }
760	        synchronize();
761	        // producer_acquire returns when at most StagesD-1 committed stores are pending
762	        bool store_finished = issued_stores > StorePipeline::UnacquiredStages;
763	        // Let dma warp know earliest smem buffer is consumed and empty after StagesD producer commits
764	        if (store_finished) {
765	          if (is_producer_load_needed) {
766	            load_pipeline.consumer_release(load_pipe_consumer_state);
767	          }
768	          ++load_pipe_consumer_state;
769	        }
770	      }
771	    };
772	
773	    //
774	    // BEGIN EPILOGUE
775	    //
776	
777	    // Pre-loop fusion callback entry point
778	    cst_callbacks.begin();
779	    if (cst_callbacks.begin_sync_needed()) {
780	      synchronize();
781	    }
782	
783	    // For each output tile
784	    CUTLASS_PRAGMA_UNROLL
785	    for (int epi_n = 0; epi_n < size<3>(gD_epi); ++epi_n) {
786	      CUTLASS_PRAGMA_UNROLL
787	      for (int epi_m = 0; epi_m < size<2>(gD_epi); ++epi_m) {
788	        [[maybe_unused]] bool is_first_iteration = epi_m == 0 && epi_n == 0;
789	        bool is_last_iteration = epi_m == size<2>(gD_epi)-1 && epi_n == size<3>(gD_epi)-1;
790	
791	        if (subtile_idx != -1 && (epi_n * static_cast<int>(size<2>(gD_epi)) + epi_m) != subtile_idx) {
792	          continue;
793	        }
794	
795	        cst_callbacks.begin_loop(epi_m, epi_n);
796	
797	        if (is_producer_load_needed) {
798	          // Wait for the producer load to fill smem
799	          load_pipeline.consumer_wait(load_wait_state);
800	
801	          if (is_C_load_needed) {
802	            // Copy source tile from smem to register
803	            copy(tiled_s2r, tSR_sC(_,_,_,load_wait_state.index()), tSR_rC);
804	            // Ensure smem loads are complete before reusing smem for mixed types/layouts
805	            if constexpr (ReuseSmemC && not (SmemLayoutC{} == SmemLayoutD{})) {
806	              synchronize();
807	            }
808	          }
809	        }
810	
811	        // First loop fusion callback entry point
812	        cst_callbacks.previsit(epi_m, epi_n, load_wait_state.count(), is_producer_load_needed);
813	
814	        if (is_producer_load_needed) {
815	          if constexpr (not ReuseSmemC) {
816	            // Let producer load warp know smem buffers are consumed and empty
817	            cutlass::arch::fence_view_async_shared();
818	            load_pipeline.consumer_release(load_pipe_consumer_state);
819	            ++load_pipe_consumer_state;
820	          }
821	          ++load_wait_state;
822	        }
823	
824	        if constexpr (epi_tile_m * epi_tile_n > mma_tile_m * mma_tile_n) {
825	          // When the epilogue subtile is larger than the MMA tiles, loop over multiple
826	          // MMA tiles
827	          static constexpr int MmaMPerEpiM = epi_tile_m / mma_tile_m;
828	          static constexpr int MmaNPerEpiN = epi_tile_n / mma_tile_n;
829	
830	          CUTLASS_PRAGMA_UNROLL
831	          for (int mma_n_in_epi = 0; mma_n_in_epi < MmaNPerEpiN; ++mma_n_in_epi) {
832	            int mma_n = (epi_n * MmaNPerEpiN) + mma_n_in_epi;
833	
834	            CUTLASS_PRAGMA_UNROLL
835	            for (int mma_m_in_epi = 0; mma_m_in_epi < MmaMPerEpiM; ++mma_m_in_epi) {
836	              int mma_m = (epi_m * MmaMPerEpiM) + mma_m_in_epi;
837	              Tensor tRS_rAcc_frg_mn = tRS_rAcc_frg(_,mma_m,mma_n);
838	              int idx_in_epi_subtile = (mma_n_in_epi * MmaMPerEpiM + mma_m_in_epi);
839	
840	              tRS_rCompute_frg(idx_in_epi_subtile) = cst_callbacks.visit(
841	                tRS_rAcc_frg_mn(0), idx_in_epi_subtile, epi_m, epi_n);
842	            }
843	          }
844	        }
845	        else {
846	          int mma_m = epi_m;
847	          int mma_n = (epi_n * size<1>(EpilogueTile{})) / mma_tile_n;
848	          Tensor tRS_rAcc_frg_mn = tRS_rAcc_frg(_,mma_m,mma_n);
849	
850	          // Vectorized fragment loop with visitor callback entry point
851	          int epi_n_in_mma = epi_n % (mma_tile_n / epi_tile_n);
852	          int r2s_v = epi_n_in_mma * size(tRS_rCompute_frg);
853	          CUTLASS_PRAGMA_UNROLL
854	          for (int epi_v = 0; epi_v < size(tRS_rCompute_frg); ++epi_v) {
855	            tRS_rCompute_frg(epi_v) = cst_callbacks.visit(tRS_rAcc_frg_mn(r2s_v + epi_v), epi_v, epi_m, epi_n);
856	          }
857	        }
858	
859	        // The latest we can delay the TMA store is right before the smem store of the next iteration
860	        // since the current TMA store needs to be committed before we can acquire the next smem buffer
861	        if constexpr (DelayTmaStore) {
862	          // Issue TMA stores for the previous subtile
863	          if (not is_first_iteration and subtile_idx == -1) {
864	            tma_store_fn(epi_m_prev, epi_n_prev);
865	          }
866	          epi_m_prev = epi_m;
867	          epi_n_prev = epi_n;
868	        }
869	        if constexpr (not ReuseSmemC) {
870	          // Wait for the smem buffer to be available
871	          if (issue_tma_store) {
872	            store_pipeline.producer_acquire(store_pipe_producer_state);
873	          }
874	          synchronize();
875	        }
876	        // Smem reduction callback entry point using current store buffer for workspace
877	        cst_callbacks.reduce(sD_epi(_,_,store_pipe_producer_state.index()),
878	                              synchronize, epi_m, epi_n, is_last_iteration, tRS_rCompute_frg);
879	
880	        // Copy tile from register to regiser if needed
881	        if constexpr (IsUseR2R) {
882	          // retile source and destination for tiled_r2r
883	          Tensor tRR_rD_src = thread_r2r.retile_S(tRS_rCompute);                             // (R2R,R2R_M,R2R_N,EPI_M,EPI_N)
884	          Tensor tRR_rD_dst = thread_r2r.retile_D(tRS_rCompute);                             // (R2R,R2R_M,R2R_N,EPI_M,EPI_N)
885	
886	          // Output register transformation before copying to shared memory.
887	          copy(tiled_r2r, tRR_rD_src, tRR_rD_dst);
888	        }
889	
890	        CUTLASS_PRAGMA_UNROLL
891	        for (int i = 0; i < size(tRS_rD_frg); ++i) {
892	          tRS_rD_frg(i) = cutlass::NumericArrayConverter<SmemElementD, RegisterElementD, FragmentSize>{}(tRS_rCompute_frg(i));
893	        }
894	        // Copy tile from register to smem
895	        if constexpr (is_destination_supported) {
896	          copy(tiled_r2s, tRS_rD, tRS_sD(_,_,_,store_pipe_producer_state.index()));
897	        }
898	
899	        // Post reduction, pre TMA store callback entry point
900	        constexpr bool issue_smem_store = true; // No smem store predication
901	        cst_callbacks.postreduce(epi_m, epi_n, store_pipe_producer_state.count(), issue_smem_store);
902	
903	        if constexpr (not DelayTmaStore) {
904	          // Issue TMA stores for this subtile
905	          tma_store_fn(epi_m, epi_n);
906	        }
907	
908	        cst_callbacks.end_loop(epi_m, epi_n);
909	
910	      } // for epi_m
911	    } // for epi_n
912	
913	    if constexpr (DelayTmaStore) {
914	      // Issue TMA stores for the last subtile
915	      tma_store_fn(epi_m_prev, epi_n_prev);
916	    }
917	
918	    // Post-loop fusion callback entry point
919	    cst_callbacks.end();
920	
921	    return cute::make_tuple(load_pipe_consumer_state, store_pipe_producer_state);
922	  }
923	
924	  CUTLASS_DEVICE auto
925	  store_tail(
926	      LoadPipeline load_pipeline,
927	      LoadPipelineState load_pipe_consumer_state,
928	      StorePipeline store_pipeline,
929	      StorePipelineState store_pipe_producer_state) {
930	    // wait for all TMA stores to complete
931	    store_pipeline.producer_tail(store_pipe_producer_state);
932	    // reset store counter
933	    issued_stores = 0;
934	
935	    if constexpr (ReuseSmemC) {
936	      if (fusion_callbacks.is_producer_load_needed()) {
937	        // Issue releases on up to StagesD-1 previously issued TMA stores
938	        constexpr int release_stages = cute::min(StorePipeline::UnacquiredStages, get_load_pipe_increment(CtaTileMNK{}));
939	        CUTLASS_PRAGMA_UNROLL
940	        for (int stage = 0; stage < release_stages; ++stage) {
941	          load_pipeline.consumer_release(load_pipe_consumer_state);
942	          ++load_pipe_consumer_state;
943	        }
944	      }
945	    }
946	
947	    return cute::make_tuple(load_pipe_consumer_state, store_pipe_producer_state);
948	  }
949	
950	private:
951	  Params const& params;
952	  FusionCallbacks fusion_callbacks;
953	  int issued_stores = 0;
954	};
955	
956	
957	/////////////////////////////////////////////////////////////////////////////////////////////////
958	
959	} // namespace collective
960	} // namespace epilogue
961	} // namespace cutlass
