153	  // Overload of step that accepts tensormaps argument, for use in ptr-array epilogues
154	  template<class Tensormaps>
155	  CUTLASS_DEVICE void
156	  step(uint64_t* full_mbarrier_ptr, int epi_m, int epi_n, int load_iteration, bool issue_tma_load, Tensormaps tensormaps) {
157	    for_each(callbacks_tuple, tensormaps,
158	      [&] (auto& callbacks, auto&& op_tensormaps) {
159	        callbacks.step(full_mbarrier_ptr, epi_m, epi_n, load_iteration, issue_tma_load, op_tensormaps);
160	      }
161	    );
162	  }
