195	  // Is a thread sync needed after begin(). Allows chaining async copies across multiple nodes
196	  CUTLASS_DEVICE bool
197	  begin_sync_needed() const {
198	    return cute::apply(callbacks_tuple,
199	      [] (auto const&... callbacks) {
200	        return (false || ... || callbacks.begin_sync_needed());
201	      }
202	    );
