242	  CUTLASS_DEVICE void
243	  reduce(STensor&& reduction_buffer, SyncFn const& sync_fn, int epi_m, int epi_n, bool is_last_iteration, VTensor visit_results) {
244	    for_each(callbacks_tuple,
